import React, { useContext, useEffect } from 'react';
import { Link } from 'react-router-dom'; // Necesario para el logo
import { Container } from 'react-bootstrap'; // Necesario para la alineación

// Importaciones de Contextos
// Solo mantenemos SettingsContext para el nombre/eslogan
import { SettingsContext } from '../context/SettingsContext'; 
// ELIMINADOS: AuthContext, CartContext, SearchBox.

const Header = () => {
  // Solo necesitamos settings para el nombre del sitio
  const { settings } = useContext(SettingsContext); 

  useEffect(() => {
    // Aplicar el color de acento de la configuración a las variables CSS globales
    if (settings?.accentColor) {
      document.documentElement.style.setProperty('--cta-color', settings.accentColor);
    }
  }, [settings]);

  // Clases base para el enlace (aseguran color blanco/gris)
  const baseLinkClasses = "text-gray-200 no-underline hover:text-white transition-colors";
  
  return (
    // CRÍTICO: Fondo negro profundo (--brand-dark) y redondeo inferior
    <header 
      className="w-full sticky top-0 z-50 transition-all duration-300 shadow-md rounded-b-xl"
      // FORZAMOS EL COLOR DE FONDO NEGRO PROFUNDO
      style={{ backgroundColor: 'var(--brand-dark)' }} 
    >
      {/* py-3 para dar espacio arriba y abajo */}
      <Container className="py-3"> 
        {/* d-flex justify-content-start para asegurar el logo a la izquierda */}
        <div className="d-flex justify-content-start align-items-center"> 
          
          {/* 1. Logo de Texto/Eslogan (ÚNICO ELEMENTO) */}
          <Link 
            to="/" 
            className={`${baseLinkClasses} flex items-center h-full flex-shrink-0`}
          > 
            <div className="d-flex flex-column align-items-start">
              {/* Nombre: Blanco, grande, negrita, mayúsculas */}
              <span className="text-white text-xl font-extrabold tracking-widest uppercase" style={{ lineHeight: 1 }}>
                {settings?.siteName || 'TECNOTITLÁN'}
              </span>
              {/* Eslogan: Gris opaco, pequeño */}
              <span className="text-gray-400 text-xs font-light tracking-wide mt-0.5" style={{ lineHeight: 1 }}>
                Tecnología con Raíces
              </span>
            </div>
          </Link>
          
          {/* Aquí termina el contenido del Header. NO HAY SEARCHBOX, CARRITO NI MENÚ DE USUARIO. */}
          
        </div>
      </Container>
    </header>
  );
};

export default Header;
